package com.company.supervision.application.scheduling;import com.company.supervision.entity.dto.schedule.ScheduleRule;import com.company.supervision.infrastructure.repository.ScheduleMapper;import com.fasterxml.jackson.databind.ObjectMapper;import org.junit.jupiter.api.Test;import org.quartz.Scheduler;import java.util.*;import static org.assertj.core.api.Assertions.*;import static org.mockito.Mockito.*;class AdvancedScheduleServiceTest{private final AdvancedScheduleService s=new AdvancedScheduleService(mock(Scheduler.class),mock(ScheduleMapper.class),new ObjectMapper(),mock(NationalWorkdayCalendar.class));@Test void compilesWeeklyRule(){ScheduleRule r=new ScheduleRule();r.setMode("WEEKLY");r.setTimes(List.of("09:30"));r.setDaysOfWeek(List.of(1,5));assertThat(s.compile(r)).containsExactly("0 30 9 ? * MON,FRI");}@Test void previewsFiveDailyRuns(){ScheduleRule r=new ScheduleRule();r.setMode("DAILY");r.setTimes(List.of("09:00"));assertThat(s.preview(r)).hasSize(5);}@Test void rejectsInvalidCron(){ScheduleRule r=new ScheduleRule();r.setMode("CRON");r.setCronExpression("bad");assertThatThrownBy(()->s.preview(r)).isInstanceOf(IllegalArgumentException.class);}}